#include<bits/stdc++.h>
using namespace std;
vector<int> mp[101];
int dp[101];
int in[101],in1[101];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        string s;
        cin>>s;
        int U=s[0]-'A'+1;
        int V=s[2]-'A'+1;
        mp[U].push_back(V);
        in1[V]++;
        queue<int> q;
        int max1=0,cnt=0;
        memcpy(in,in1,sizeof(in1));
        memset(dp,0,sizeof(dp));
        for(int i=1;i<=n;i++)
        {
            if(in[i]==0)
            {
                q.push(i);
                dp[i]=1;
            }
        }
        vector<int> v;
        while(!q.empty())
        {
            int t=q.front();
            q.pop();
            v.push_back(t);
            cnt++;
            for(int i:mp[t])
            {
                in[i]--;
                dp[i]=max(dp[i],dp[t]+1);
                max1=max(max1,dp[i]);
                if(in[i]==0)
                {
                    q.push(i);
                }
            }
        }
        if(cnt!=n)
        {
            printf("Inconsistency found after %d relations.",i);
            return 0;
        }
        if(max1==n)
        {
            printf("Sorted sequence determined after %d relations: ",i);
            for(int j:v)
            {
                printf("%c",(char)(j+'A'-1));
            }
            printf(".");
            return 0;
        }
    }
    printf("Sorted sequence cannot be determined.");
    return 0;
}
